WITH pattern_union_r AS (
(SELECT 'TestUser' AS start_type, string(from_node.user_id) as start_id, string(to_node.user_id) as end_id, 'TestUser' AS end_type, array('TEST_FOLLOWS') as path_relationships, array(to_json(struct(test_integration.follows.since AS since))) as rel_properties, to_json(struct(from_node.age, from_node.name, from_node.user_id)) as start_properties, to_json(struct(to_node.age, to_node.name, to_node.user_id)) as end_properties, NULL AS purchase_date, NULL AS quantity, test_integration.follows.since AS since FROM test_integration.follows INNER JOIN test_integration.users AS from_node ON from_node.user_id = test_integration.follows.follower_id INNER JOIN test_integration.users AS to_node ON to_node.user_id = test_integration.follows.followed_id)
UNION ALL
(SELECT 'TestUser' AS start_type, string(from_node.user_id) as start_id, string(to_node.user_id) as end_id, 'TestUser' AS end_type, array('TEST_FRIENDS_WITH') as path_relationships, array(to_json(struct(test_integration.friendships.since AS since))) as rel_properties, to_json(struct(from_node.age, from_node.name, from_node.user_id)) as start_properties, to_json(struct(to_node.age, to_node.name, to_node.user_id)) as end_properties, NULL AS purchase_date, NULL AS quantity, test_integration.friendships.since AS since FROM test_integration.friendships INNER JOIN test_integration.users AS from_node ON from_node.user_id = test_integration.friendships.user_id_1 INNER JOIN test_integration.users AS to_node ON to_node.user_id = test_integration.friendships.user_id_2)
UNION ALL
(SELECT 'TestUser' AS start_type, string(test_integration.users.user_id) as start_id, string(test_integration.products.product_id) as end_id, 'TestProduct' AS end_type, array('TEST_PURCHASED') as path_relationships, array(to_json(struct(test_integration.purchases.purchase_date AS purchase_date, test_integration.purchases.quantity AS quantity))) as rel_properties, to_json(struct(test_integration.users.age, test_integration.users.name, test_integration.users.user_id)) as start_properties, to_json(struct(test_integration.products.category, test_integration.products.name, test_integration.products.price, test_integration.products.product_id)) as end_properties, test_integration.purchases.purchase_date AS purchase_date, test_integration.purchases.quantity AS quantity, NULL AS since FROM test_integration.purchases INNER JOIN test_integration.users ON test_integration.users.user_id = test_integration.purchases.user_id INNER JOIN test_integration.products ON test_integration.products.product_id = test_integration.purchases.product_id)
)
SELECT 
      count(r.start_id) AS `total`
FROM pattern_union_r AS r
